import{_ as t,o as e,c as a,a4 as l}from"./chunks/framework.Bz0lZ1uX.js";const q=JSON.parse('{"title":"弗雷德里克·图多·戈里 - 人工制冷时代的开创者","description":"","frontmatter":{},"headers":[],"relativePath":"materials/人物素材/企业家与发明家/弗雷德里克·图多·戈里.md","filePath":"materials/人物素材/企业家与发明家/弗雷德里克·图多·戈里.md","lastUpdated":null}'),s={name:"materials/人物素材/企业家与发明家/弗雷德里克·图多·戈里.md"},r=l('<h1 id="弗雷德里克·图多·戈里-人工制冷时代的开创者" tabindex="-1">弗雷德里克·图多·戈里 - 人工制冷时代的开创者 <a class="header-anchor" href="#弗雷德里克·图多·戈里-人工制冷时代的开创者" aria-label="Permalink to &quot;弗雷德里克·图多·戈里 - 人工制冷时代的开创者&quot;">​</a></h1><p><strong>标签</strong>: #发明家 #创新 #勇气 #打破垄断 #科技改变生活 #挑战权威 #时代变革</p><hr><h2 id="核心事迹简介" tabindex="-1">核心事迹简介 <a class="header-anchor" href="#核心事迹简介" aria-label="Permalink to &quot;核心事迹简介&quot;">​</a></h2><p>弗雷德里克·图多·戈里，19世纪美国发明家与企业家。面对当时垄断北美市场的天然冰业巨头&quot;冰王&quot;弗雷德里克·图多，戈里没有退缩，而是潜心研发人工制冰技术。他克服技术瓶颈与市场打压，最终使机械制冷成本低于天然采冰，打破了图多的冰业帝国，开启了人工制冷的新纪元，深刻改变了食品保鲜、医疗存储与日常生活。</p><hr><h2 id="考场议论文论证片段" tabindex="-1">考场议论文论证片段 <a class="header-anchor" href="#考场议论文论证片段" aria-label="Permalink to &quot;考场议论文论证片段&quot;">​</a></h2><h3 id="片段1-个人品质角度" tabindex="-1">片段1（个人品质角度） <a class="header-anchor" href="#片段1-个人品质角度" aria-label="Permalink to &quot;片段1（个人品质角度）&quot;">​</a></h3><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>真正的勇气，不是无所畏惧，而是在巨人的阴影下依然选择前行。当戈里投身人工制冰研究时，&quot;冰王&quot;图多的天然冰帝国已盘踞北美数十年，从湖泊采冰到跨洋运输，整条产业链固若金汤。戈里却看穿天然冰受制于季节与气候的致命软肋，在简陋的实验室中反复调试压缩循环装置。面对图多的市场封锁与同行的嘲讽，他始终埋首于蒸汽与氨气的世界，最终以可控的机械之力，战胜了不可控的自然之力。这份敢于向垄断者亮剑的胆识与韧性，正是创新者最可贵的品格。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="片段2-时代价值角度" tabindex="-1">片段2（时代价值角度） <a class="header-anchor" href="#片段2-时代价值角度" aria-label="Permalink to &quot;片段2（时代价值角度）&quot;">​</a></h3><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>技术的迭代，往往始于对旧秩序的颠覆，终于对人类福祉的拓展。戈里的人工制冰不仅终结了图多的商业霸权，更解放了食品工业于季节的囚笼——肉类可以跨洲保鲜，疫苗能够常年储存，热带地区首次尝到了冰镇的滋味。从芝加哥的屠宰场到新加坡的港口，机械制冷的轰鸣声宣告了一个不受自然支配的新时代的到来。戈里的胜利，实质上是人类以科技驯服自然、以创新打破垄断的缩影，其影响远超商业竞争本身，重塑了现代文明的物质基础。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><h2 id="适用高考作文主题" tabindex="-1">适用高考作文主题 <a class="header-anchor" href="#适用高考作文主题" aria-label="Permalink to &quot;适用高考作文主题&quot;">​</a></h2><p>创新 · 勇气 · 打破垄断 · 科技改变生活 · 挑战权威 · 时代变革</p><hr><h2 id="高中作文写作建议" tabindex="-1">高中作文写作建议 <a class="header-anchor" href="#高中作文写作建议" aria-label="Permalink to &quot;高中作文写作建议&quot;">​</a></h2><table><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">具体建议</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>段落位置</strong></td><td style="text-align:left;">适用于&quot;新旧对比&quot;&quot;打破常规&quot;类分论点，或与&quot;柯达胶卷&quot;&quot;诺基亚&quot;等守成者反面案例对照使用</td></tr><tr><td style="text-align:left;"><strong>过渡句式</strong></td><td style="text-align:left;">&quot;当众人习惯于向自然索取时，戈里却选择向技术要答案&quot;&quot;从图多的冰船到戈里的压缩机，变的不仅是制冰方式，更是人类面对自然的姿态&quot;</td></tr><tr><td style="text-align:left;"><strong>扣题方法</strong></td><td style="text-align:left;">叙述&quot;冰王&quot;垄断背景后，突出戈里&quot;明知不可为而为之&quot;的选择，再点明这一选择如何体现&quot;创新/勇气&quot;主题</td></tr><tr><td style="text-align:left;"><strong>立意升格</strong></td><td style="text-align:left;">可延伸至&quot;新质生产力&quot;&quot;颠覆性创新&quot;等时政概念，或对比当下&quot;卡脖子&quot;技术突围，强调打破垄断对时代进步的推动作用</td></tr></tbody></table><hr><h2 id="补充素材推荐" tabindex="-1">补充素材推荐 <a class="header-anchor" href="#补充素材推荐" aria-label="Permalink to &quot;补充素材推荐&quot;">​</a></h2><table><thead><tr><th style="text-align:left;">类别</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>名言</strong></td><td style="text-align:left;">&quot;创新是将想象变为现实的桥梁&quot;——约瑟夫·熊彼特</td></tr><tr><td style="text-align:left;"><strong>对比人物</strong></td><td style="text-align:left;">柯达公司——固守胶片技术而被数码时代淘汰</td></tr><tr><td style="text-align:left;"><strong>同类素材</strong></td><td style="text-align:left;">贝尔 vs. 西部联合电报公司（电话专利之争）；马斯克 vs. 传统航天（可回收火箭）</td></tr></tbody></table>',20),o=[r];function n(i,d,h,u,c,p){return e(),a("div",null,o)}const b=t(s,[["render",n]]);export{q as __pageData,b as default};
